import{_ as d,o,c as i,a2 as a}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"Codex-to-IM 当前架构","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/current.md","filePath":"architecture/current.md","lastUpdated":1780509827000}'),c={name:"architecture/current.md"};function s(t,e,l,n,r,h){return o(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="codex-to-im-当前架构" tabindex="-1">Codex-to-IM 当前架构 <a class="header-anchor" href="#codex-to-im-当前架构" aria-label="Permalink to &quot;Codex-to-IM 当前架构&quot;">​</a></h1><p>本文描述 Codex-to-IM 当前真实运行架构、核心概念、数据归属和主要工作流。它不是未来规划文档，而是用来回答两个问题：</p><ul><li>现在系统如何把本地 Codex 线程接到 IM。</li><li><code>codex_thread_id -&gt; BridgeSession -&gt; ChannelChat -&gt; IMChannel</code> 这条链路里，每一层到底负责什么。</li></ul><p>当前产品形态是本地可安装应用：</p><ul><li><code>codex-to-im open</code>：启动本地 Web 工作台，并尝试启动 bridge。</li><li><code>codex-to-im start</code>：只启动 bridge。</li><li><code>codex-to-im status</code>、<code>url</code>、<code>stop</code>、<code>autostart</code>、<code>uninstall</code>：本地服务管理命令，由 <code>src/entrypoints/cli.ts</code> 和 <code>src/local-service/manager.ts</code> 实现。</li><li>配置和运行数据放在 <code>~/.codex-to-im</code>；项目不要求安装流程写入 <code>~/.codex/config.toml</code>。</li></ul><h2 id="核心身份链路" tabindex="-1">核心身份链路 <a class="header-anchor" href="#核心身份链路" aria-label="Permalink to &quot;核心身份链路&quot;">​</a></h2><p>Codex-to-IM 的核心不是“一个 IM 聊天等于一个 Codex 线程”。正确链路是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Codex thread</span></span>
<span class="line"><span>  -&gt; BridgeSession</span></span>
<span class="line"><span>  -&gt; ChannelChat</span></span>
<span class="line"><span>  -&gt; IMChannel / IM chat</span></span></code></pre></div><p>更具体地说：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.codex/sessions/**/*.jsonl</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        | thread id</span></span>
<span class="line"><span>        v</span></span>
<span class="line"><span>BridgeSession.codex_thread_id</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        | BridgeSession.id</span></span>
<span class="line"><span>        v</span></span>
<span class="line"><span>ChannelChat.bridgeSessionId</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        | channelType + chatId</span></span>
<span class="line"><span>        v</span></span>
<span class="line"><span>飞书里的某个聊天</span></span></code></pre></div><p>这条链路有几个关键规则：</p><ul><li><code>codex_thread_id</code> 只属于 <code>BridgeSession</code>。</li><li><code>ChannelChat</code> 不保存 Codex thread id，只保存 <code>bridgeSessionId</code>。</li><li>IM 消息进来时，bridge 先按 channel 和 chat 找到 ChannelChat，再读取 ChannelChat 指向的 <code>BridgeSession</code>，最后从 session 上取 <code>codex_thread_id</code> 来继续或镜像 Codex 线程。</li><li>一个 <code>BridgeSession</code> 可以先存在，之后才产生 <code>codex_thread_id</code>。</li><li>一个 IM chat 只保存一个 ChannelChat；一个 <code>BridgeSession</code> 也只保留一个聊天绑定。</li><li>一个通道实例只是消息入口，不等于会话，也不等于 Codex thread。</li></ul><h2 id="codex-thread" tabindex="-1">Codex Thread <a class="header-anchor" href="#codex-thread" aria-label="Permalink to &quot;Codex Thread&quot;">​</a></h2><p>Codex thread 是 Codex 自己的对话线程。Codex-to-IM 不拥有它，只记录它的 id。</p><p>Codex thread 可以来自不同入口：</p><ul><li>IM 里发起的一次 SDK turn。</li><li>本地 Codex CLI / TUI 会话。</li><li>本地 Codex Native 客户端产生的会话。</li><li>被 <code>/t</code> 从本地 Codex session 列表接管的已有线程。</li></ul><p>Codex-to-IM 读取 Codex 自己的数据：</p><ul><li><code>~/.codex/sessions/**/*.jsonl</code>：Codex 会话事件。</li><li><code>~/.codex/state_*.sqlite</code>：本地 session 列表兼容元数据，只读使用。</li></ul><p>这些文件不属于 Codex-to-IM。Codex-to-IM 可以读取、索引、展示和镜像它们，但不应把它们当作自己的主存储。</p><h2 id="bridgesession" tabindex="-1">BridgeSession <a class="header-anchor" href="#bridgesession" aria-label="Permalink to &quot;BridgeSession&quot;">​</a></h2><p><code>BridgeSession</code> 是 Codex-to-IM 自己拥有的本地产品会话，保存在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.codex-to-im/data/sessions.json</span></span></code></pre></div><p>它用本地 <code>BridgeSession.id</code> 作为主键，负责承载“这个可持续对话在 Codex-to-IM 里的状态”。</p><p>它保存：</p><ul><li>会话名。</li><li>工作目录。</li><li>模型、模式、reasoning、sandbox、network、provider 等运行设置。</li><li>可选的 <code>codex_thread_id</code>。</li><li>运行状态、队列状态、健康状态。</li><li>流式 UI 状态、mirror 状态和诊断信息。</li><li>Bridge 自己的消息缓存索引。</li></ul><p><code>BridgeSession</code> 和 Codex thread 的关系是“本地会话容器指向 Codex thread”：</p><ul><li>没有 <code>codex_thread_id</code>：这个 Bridge 会话还没有真实 Codex thread，可能只是一个新建会话、草稿会话或尚未发起过 turn 的会话。</li><li>有 <code>codex_thread_id</code>：这个 Bridge 会话已经关联一个真实 Codex thread，后续 history、mirror、resume 都通过这个 id 找 Codex 数据。</li></ul><p>旧字段不再参与业务判断：</p><ul><li><code>sdk_session_id</code></li><li><code>sdkSessionId</code></li><li><code>desktop_thread_id</code></li><li><code>desktopThreadId</code></li><li><code>thread_origin</code></li><li><code>threadOrigin</code></li><li><code>thread_id</code></li><li><code>threadId</code></li></ul><p>这些字段只允许作为迁移输入出现；运行时代码不应把它们当成 fallback。</p><h2 id="channelchat" tabindex="-1">ChannelChat <a class="header-anchor" href="#channelchat" aria-label="Permalink to &quot;ChannelChat&quot;">​</a></h2><p><code>ChannelChat</code> 是“某个 IM chat 绑定到哪个 BridgeSession”的关系，保存在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.codex-to-im/data/channel-chats.json</span></span></code></pre></div><p>它保存：</p><ul><li>通道身份：<code>channelType</code>、可选 provider、通道别名。</li><li>聊天身份：<code>chatId</code>、可选聊天类型 <code>chatKind</code>、可选用户 id。</li><li><code>bridgeSessionId</code>：指向一个 <code>BridgeSession.id</code>。</li></ul><p><code>ChannelChat</code> 不拥有 Codex thread 身份，也不保存工作目录、模型、模式、显示名等运行时字段。它的职责只到 <code>bridgeSessionId</code> 为止。</p><p>普通消息的解析路径是：</p><ol><li>飞书 adapter 收到一条消息。</li><li>bridge 根据 channel instance 和 chat id 找到当前聊天的 ChannelChat。</li><li>ChannelChat 给出 <code>bridgeSessionId</code>。</li><li>store 读取对应 <code>BridgeSession</code>。</li><li>如果 session 有 <code>codex_thread_id</code>，就 resume 对应 Codex thread。</li><li>如果 session 没有 <code>codex_thread_id</code>，就创建或启动新的 Codex turn，并把返回的 thread id 写回 <code>BridgeSession.codex_thread_id</code>。</li></ol><p>因此，<code>ChannelChat</code> 是 IM 世界和 Bridge 会话世界之间的连接点，不是 Codex thread 的存放点。</p><h2 id="imchannel" tabindex="-1">IMChannel <a class="header-anchor" href="#imchannel" aria-label="Permalink to &quot;IMChannel&quot;">​</a></h2><p><code>IMChannel</code> 是配置好的 IM 入口。当前支持飞书。</p><p>一个通道实例包含：</p><ul><li>provider：飞书。</li><li>实例 id。</li><li>别名。</li><li>是否启用。</li><li>平台凭据和连接配置。</li><li>运行期 adapter 状态。</li></ul><p>多个通道实例可以同时存在，例如：</p><ul><li>飞书主号。</li><li>飞书备份号。</li></ul><p>通道实例不是会话。它只是让某个平台的消息进入 bridge，并把 bridge 输出送回平台。真正的会话身份仍然在 <code>BridgeSession</code>，聊天到会话的关系仍然在 <code>ChannelChat</code>。</p><h2 id="一条-im-消息如何进入-runtime" tabindex="-1">一条 IM 消息如何进入 Runtime <a class="header-anchor" href="#一条-im-消息如何进入-runtime" aria-label="Permalink to &quot;一条 IM 消息如何进入 Runtime&quot;">​</a></h2><p>普通 IM 文本消息进入当前 runtime 的主路径：</p><ol><li>平台 adapter 接收飞书消息，生成 <code>InboundMessage</code>。</li><li><code>bridge-manager.ts</code> 判断它是权限回调、命令还是普通 prompt。</li><li>如果是普通 prompt，<code>channel-router.ts</code> 解析当前 chat 的 ChannelChat。</li><li>ChannelChat 指向 <code>BridgeSession.id</code>。</li><li><code>interactive-turn/runner.ts</code> 建立本次 turn 的任务状态和流式反馈。</li><li><code>CodexRoutingProvider</code> 根据会话 runtime 与 provider 设置路由：Codex 支持 <code>sdk</code>、<code>pty</code>、<code>tmux</code>，Claude 支持 <code>pty</code>、<code>sdk</code>。</li><li>provider 创建或继续对应 runtime 的会话身份，例如 Codex thread 或 Claude <code>session_id</code>。</li><li>如果 provider 返回 runtime identity，写入 <code>BridgeSession.runtime</code> 对应容器。</li><li>delivery pipeline 把最终文本、卡片、附件等发回对应 IM channel。</li></ol><p>这条路径保证“IM 只是入口，BridgeSession 才是本地会话，Codex thread 才是真正的 Codex 对话”。</p><h2 id="t-接管本地-codex-线程" tabindex="-1"><code>/t</code> 接管本地 Codex 线程 <a class="header-anchor" href="#t-接管本地-codex-线程" aria-label="Permalink to &quot;\`/sites/codelark/t\` 接管本地 Codex 线程&quot;">​</a></h2><p><code>/t</code> 命令用于把本机可发现的 Codex thread 接入 IM。</p><p>典型过程：</p><ol><li>用户发送 <code>/t</code>。</li><li>local Codex session index 扫描 <code>~/.codex/sessions/**/*.jsonl</code>。</li><li>bridge 返回最近的本地 Codex 线程列表。</li><li>用户发送 <code>/t 1</code>。</li><li>被选中的 Codex thread 会被 materialize 成一个 <code>BridgeSession</code>，或复用已有同 thread 的 <code>BridgeSession</code>。</li><li>当前 IM chat 创建或更新 <code>ChannelChat</code>，让它指向这个 <code>BridgeSession.id</code>。</li><li>后续普通消息通过 ChannelChat 找到 session，再通过 <code>BridgeSession.codex_thread_id</code> 继续同一条 Codex thread。</li></ol><p>因此 <code>/t</code> 不是“把 thread id 写到聊天上”，而是“把 Codex thread 纳入 BridgeSession，再让聊天绑定这个 BridgeSession”。</p><h2 id="mirror-运行时" tabindex="-1">Mirror 运行时 <a class="header-anchor" href="#mirror-运行时" aria-label="Permalink to &quot;Mirror 运行时&quot;">​</a></h2><p>Mirror 是对本地 runtime JSONL 文件的持续观察。Codex 和 Claude Code 各自有底层 JSONL source，但共用 <code>mirror-runtime.ts</code>、<code>mirror-turns.ts</code> 和 <code>mirror-feedback-controller.ts</code> 这套 reducer / delivery 管线。</p><p>主路径：</p><ol><li><code>mirror-subscription-registry.ts</code> 找到有本地 runtime 身份的 <code>BridgeSession</code>。</li><li>再找到绑定这些 session 的 <code>ChannelChat</code>。</li><li><code>mirror-runtime.ts</code> 根据绑定关系建立或更新订阅。</li><li>每个订阅通过当前 runtime 的 source 定位对应 JSONL 文件。</li><li>文件监听和定时 reconcile 读取新增记录。</li><li>suppression 去掉当前 IM 发起 turn 造成的重复回显。</li><li><code>mirror-turns.ts</code> 把 JSONL 事件合并成可展示 turn。</li><li><code>mirror-feedback-controller.ts</code> 更新流式卡片或发送最终 fallback 消息。</li><li>如果这批记录包含可被当前 active turn 接受的 <code>task_complete</code> / <code>task_aborted</code>，<code>routeRuntimeRecords</code> 会通过 <code>TurnCoordinator.claimRuntimeTerminal</code> 把终态归还给 active turn。Codex 和 Claude Code 使用同一个接口；普通 Claude IM turn 仍保留 mirror 卡片作为首屏 反馈路径，不会被 terminal claim 抢成 <code>im:</code> 流。</li></ol><p>Codex mirror 的身份链路是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codex_thread_id -&gt; BridgeSession -&gt; ChannelChat -&gt; channel/chat</span></span></code></pre></div><p>Claude Code mirror 的身份链路是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>runtime.claude.sessionId + runtime.claude.cwd -&gt; BridgeSession -&gt; ChannelChat -&gt; channel/chat</span></span></code></pre></div><p>如果 JSONL source 连续多次无法定位，<code>mirror-runtime.ts</code> 会通过 runtime-neutral identity cleanup hook 清理当前 runtime 身份：Codex 清理 <code>runtime.codex.threadId</code>，Claude Code 清理 <code>runtime.claude.sessionId</code> / <code>runtime.claude.cwd</code>。这样 dangling 本地线程不会在 subscription registry 里反复重建。</p><p>解析出来。<code>routeCodexRecords</code> 和 <code>claimCodexTerminal</code> 仍作为兼容入口保留， 新代码应优先使用 runtime-neutral 的 <code>routeRuntimeRecords</code> 和 <code>claimRuntimeTerminal</code>。</p><h2 id="命令应用层" tabindex="-1">命令应用层 <a class="header-anchor" href="#命令应用层" aria-label="Permalink to &quot;命令应用层&quot;">​</a></h2><p>Slash command 主要由 <code>src/bridge/command/dispatch.ts</code> 分发。当前 command 目录已经按一部分工作流拆分：</p><ul><li><code>session-thread.ts</code>：线程选择、切换、重命名；纯参数解析、命名校验和 <code>/clear</code> 确认卡片在 <code>session-args.ts</code>。</li><li><code>runtime-settings.ts</code>：mode、reasoning、sandbox、network、model、工作目录和 UI detail 等运行设置入口；同时 re-export 旧 provider/bootstrap helper 入口。</li><li><code>provider-settings.ts</code>：<code>/provider</code> 的 Codex/Claude provider 切换编排。</li><li><code>runtime-bootstrap.ts</code>：Codex thread 预创建和 SDK SSE thread id 解析。</li><li><code>runtime-session.ts</code>：runtime session 映射、创建、格式化和 provider 阻断提示 helper。</li><li><code>tmux.ts</code>：tmux provider 控制；纯 tmux 参数、按键和 screen 参数解析在 <code>tmux-args.ts</code>。</li><li><code>pty.ts</code>：pty provider 屏幕观察和定时刷新。</li><li><code>shell.ts</code>：远程 shell 命令执行。</li><li><code>auto.ts</code>：自动任务。</li><li><code>status.ts</code>、<code>diagnostics.ts</code>：状态和诊断。</li><li><code>global-settings.ts</code>：全局设置。</li><li><code>hot-update.ts</code>：热更新。</li><li><code>presentation/</code>：命令展示格式；根部 <code>presentation.ts</code>、<code>auto-presentation.ts</code>、<code>diagnostics-presentation.ts</code> 仅保留兼容 re-export。</li></ul><p>命令可以分为三类：</p><ul><li>通道级命令：不要求当前 chat 已经有 session，例如 <code>/status</code>、<code>/t</code>。</li><li>会话级命令：读取或修改当前 chat 的 ChannelChat/session，例如 <code>/new</code>、<code>/t 1</code>、<code>/provider</code>、<code>/his</code>、<code>/stop</code>。</li><li>全局配置命令：通过某个 chat 触发，但实际修改全局设置，例如 <code>/ui</code>、<code>/his limit</code>。</li></ul><p>Command 重构的当前完成标准是模块边界优先，而不是继续把每条命令拆得很细：</p><ul><li><code>bridge/host</code> 是生产代码里唯一直接调用 <code>bridge/command</code> 的上层 owner。</li><li><code>channels</code>、<code>bridge/turn</code>、<code>runtime</code>、<code>storage</code>、<code>operator-ui</code> 不直接依赖 <code>bridge/command</code>。</li><li>跨命令和 turn 共用的回调协议放在 <code>src/bridge/callbacks/</code>，避免 turn 反向依赖 command。</li><li>command 不直接 import <code>bridge/host/*</code>：全局 bridge context 位于 <code>src/bridge/context.ts</code>，会话绑定 router 位于 <code>src/bridge/session/channel-router.ts</code>，startup notice target 位于 <code>src/bridge/startup-notice-target.ts</code>；<code>src/bridge/host/*</code> 同名文件仅保留兼容 facade。</li></ul><h2 id="本地工作台" tabindex="-1">本地工作台 <a class="header-anchor" href="#本地工作台" aria-label="Permalink to &quot;本地工作台&quot;">​</a></h2><p>本地 Web 工作台由 <code>src/operator-ui/server.ts</code> 提供页面和 API。</p><p>主要页面：</p><ul><li>概览：显示 UI、bridge、通道数量和进程状态。</li><li>Sessions：列出 Bridge 会话和本机可发现的 Codex 线程。</li><li>Session History：查看某个 session 的历史。</li><li>Channels：管理飞书通道实例、ChannelChat、默认目标和测试。</li><li>Config：编辑全局默认设置。</li><li>命令：展示 IM 命令帮助。</li></ul><p>UI 里的可变操作应使用 <code>BridgeSession.id</code>。本机 Codex thread 在未 materialize 前只能作为只读 local-index row 展示；一旦用户对它执行重命名、绑定、配置、删除或设置默认目标等操作，就应先 materialize 成 <code>BridgeSession</code>。</p><h2 id="数据归属" tabindex="-1">数据归属 <a class="header-anchor" href="#数据归属" aria-label="Permalink to &quot;数据归属&quot;">​</a></h2><p>Codex-to-IM 自有数据位于 <code>~/.codex-to-im</code>：</p><ul><li><code>config.v2.json</code>：结构化配置。</li><li><code>config.env</code>：兼容旧工具的配置快照和 bootstrap 输入，不是多实例通道配置的完整来源。</li><li><code>data/sessions.json</code>：BridgeSession，包含唯一的 <code>codex_thread_id</code>。</li><li><code>data/channel-chats.json</code>：ChannelChat，只保存 IM chat 身份和 <code>bridgeSessionId</code>。</li><li><code>data/channel-default-targets.json</code>：通道实例的默认目标。</li><li><code>data/messages/&lt;sessionId&gt;.json</code>：Bridge 消息缓存。</li><li><code>data/permissions.json</code>：权限回调链接。</li><li><code>data/offsets.json</code>：adapter 消费偏移。</li><li><code>data/dedup.json</code>：去重时间戳。</li><li><code>data/audit.json</code>：审计记录。</li><li><code>thread-table-messages.json</code>：线程卡片消息记录。</li><li>bridge 和 UI 的 runtime 状态文件。</li></ul><p>Codex 自有数据仍位于 <code>~/.codex</code>。Codex-to-IM 只读使用它们。</p><h2 id="迁移边界" tabindex="-1">迁移边界 <a class="header-anchor" href="#迁移边界" aria-label="Permalink to &quot;迁移边界&quot;">​</a></h2><p>启动迁移负责把旧 session thread 身份字段收敛到 <code>BridgeSession.codex_thread_id</code>。旧 <code>data/bindings.json</code> 到 <code>data/channel-chats.json</code> 的迁移使用显式脚本执行，不在运行时代码中保留兼容读取：</p><ul><li>session 上旧的 <code>sdk_session_id</code>、<code>desktop_thread_id</code>、<code>thread_id</code> 会迁移成 <code>codex_thread_id</code>。</li><li><code>scripts/migrate-bindings-to-channel-chats.js</code> 只保留旧 binding 中 <code>active: true</code> 的记录，并把旧 binding 上的运行时字段迁到它指向的 session 空字段；成功写入 <code>channel-chats.json</code> 后会删除旧 <code>data/bindings.json</code>。</li><li>旧 selector 字符串只允许作为迁移输入；运行时代码应使用 <code>BridgeSession.id</code> 和显式的 Codex thread import。</li></ul><p>迁移后的不变量：</p><ul><li>Codex thread 身份只在 session。</li><li>ChannelChat 只指向 session。</li><li>channel 只负责平台入口和消息投递。</li></ul><h2 id="术语规则" tabindex="-1">术语规则 <a class="header-anchor" href="#术语规则" aria-label="Permalink to &quot;术语规则&quot;">​</a></h2><ul><li>使用 <code>codex_thread_id</code> 表示唯一持久化的 Codex thread 身份。</li><li>不新增 <code>thread_id</code> 作为替代字段。</li><li>不把 <code>sdk_session_id</code>、<code>desktop_thread_id</code>、<code>thread_origin</code> 当运行时 fallback。</li><li>用户文案可以使用“本地 Codex 会话”或“Codex 线程”。</li><li>内部业务模型围绕 <code>BridgeSession</code>、<code>ChannelChat</code>、<code>IMChannel</code> 和 <code>codex_thread_id</code> 表达。</li><li><code>ChannelChat</code> 是 chat 到 BridgeSession 的关系，不是 chat 到 Codex thread 的关系。</li></ul>`,88)])])}const C=d(c,[["render",s]]);export{u as __pageData,C as default};
